import json
import boto3
import os
import hashlib
import re
from urllib.parse import unquote_plus
from botocore.exceptions import ClientError
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

ALLOWED_EXTENSIONS = {'.jpg', '.jpeg', '.png', '.gif', '.bmp', '.webp'}
MAX_FILE_SIZE = 10 * 1024 * 1024  # 10MB
ALLOWED_BUCKET_PATTERN = re.compile(r'^[a-z0-9][a-z0-9\-]{1,61}[a-z0-9]$')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN')
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET')

def validate_s3_key(key):
    """Validate S3 key to prevent path traversal and injection attacks"""
    if not key or len(key) > 1024:
        raise ValueError("Invalid key length")
    
    decoded_key = unquote_plus(key)
    
    if '..' in decoded_key or decoded_key.startswith('/'):
        raise ValueError("Path traversal attempt detected")
    
    if any(char in decoded_key for char in ['\x00', '\n', '\r']):
        raise ValueError("Invalid characters in key")
    
    return decoded_key

def validate_bucket_name(bucket):
    """Validate S3 bucket name"""
    if not bucket or not ALLOWED_BUCKET_PATTERN.match(bucket):
        raise ValueError("Invalid bucket name")
    return bucket

def validate_file_extension(filename):
    """Validate file has allowed extension"""
    ext = os.path.splitext(filename.lower())[1]
    if ext not in ALLOWED_EXTENSIONS:
        raise ValueError(f"File extension {ext} not allowed")
    return True

def sanitize_for_logging(data):
    """Remove sensitive information before logging"""
    if isinstance(data, dict):
        sanitized = {}
        sensitive_keys = {'authorization', 'token', 'password', 'secret', 'key'}
        for k, v in data.items():
            if any(sens in k.lower() for sens in sensitive_keys):
                sanitized[k] = '***REDACTED***'
            else:
                sanitized[k] = sanitize_for_logging(v)
        return sanitized
    elif isinstance(data, list):
        return [sanitize_for_logging(item) for item in data]
    return data

def process_image(bucket, key):
    """Process image with security validations"""
    try:
        response = s3_client.head_object(Bucket=bucket, Key=key)
        
        content_length = response.get('ContentLength', 0)
        if content_length > MAX_FILE_SIZE:
            raise ValueError(f"File size {content_length} exceeds maximum {MAX_FILE_SIZE}")
        
        content_type = response.get('ContentType', '')
        allowed_content_types = {'image/jpeg', 'image/png', 'image/gif', 'image/bmp', 'image/webp'}
        if content_type not in allowed_content_types:
            raise ValueError(f"Content type {content_type} not allowed")
        
        obj = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = obj['Body'].read()
        
        if len(image_data) > MAX_FILE_SIZE:
            raise ValueError("Actual file size exceeds maximum")
        
        file_hash = hashlib.sha256(image_data).hexdigest()
        
        result = {
            'original_key': key,
            'file_hash': file_hash,
            'size': len(image_data),
            'content_type': content_type,
            'status': 'processed'
        }
        
        return result, image_data
        
    except ClientError as e:
        error_code = e.response.get('Error', {}).get('Code', 'Unknown')
        if error_code == 'NoSuchKey':
            raise ValueError("File not found")
        elif error_code == 'AccessDenied':
            raise ValueError("Access denied to file")
        else:
            raise ValueError(f"S3 error: {error_code}")

def write_results_to_s3(result_data, original_key):
    """Write processing results to S3 with validation"""
    if not OUTPUT_BUCKET:
        raise ValueError("OUTPUT_BUCKET environment variable not set")
    
    validate_bucket_name(OUTPUT_BUCKET)
    
    safe_filename = os.path.basename(original_key)
    output_key = f"processed/{hashlib.sha256(safe_filename.encode()).hexdigest()[:16]}/{safe_filename}.json"
    
    s3_client.put_object(
        Bucket=OUTPUT_BUCKET,
        Key=output_key,
        Body=json.dumps(result_data),
        ContentType='application/json',
        ServerSideEncryption='AES256'
    )
    
    return output_key

def send_notification(message_data):
    """Send SNS notification with validation"""
    if not SNS_TOPIC_ARN:
        raise ValueError("SNS_TOPIC_ARN environment variable not set")
    
    if not SNS_TOPIC_ARN.startswith('arn:aws:sns:'):
        raise ValueError("Invalid SNS topic ARN format")
    
    sanitized_message = sanitize_for_logging(message_data)
    
    sns_client.publish(
        TopicArn=SNS_TOPIC_ARN,
        Message=json.dumps(sanitized_message),
        Subject='Image Processing Complete'
    )

def lambda_handler(event, context):
    """
    Lambda function to process images from S3
    
    Required IAM Role Policy (Least Privilege):
    {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Action": [
                    "s3:GetObject",
                    "s3:HeadObject"
                ],
                "Resource": "arn:aws:s3:::SOURCE_BUCKET_NAME/*"
            },
            {
                "Effect": "Allow",
                "Action": [
                    "s3:PutObject"
                ],
                "Resource": "arn:aws:s3:::OUTPUT_BUCKET_NAME/processed/*",
                "Condition": {
                    "StringEquals": {
                        "s3:x-amz-server-side-encryption": "AES256"
                    }
                }
            },
            {
                "Effect": "Allow",
                "Action": [
                    "sns:Publish"
                ],
                "Resource": "arn:aws:sns:REGION:ACCOUNT_ID:TOPIC_NAME"
            },
            {
                "Effect": "Allow",
                "Action": [
                    "logs:CreateLogGroup",
                    "logs:CreateLogStream",
                    "logs:PutLogEvents"
                ],
                "Resource": "arn:aws:logs:REGION:ACCOUNT_ID:log-group:/aws/lambda/FUNCTION_NAME:*"
            }
        ]
    }
    
    Environment Variables Required:
    - SNS_TOPIC_ARN: ARN of SNS topic for notifications
    - OUTPUT_BUCKET: Name of S3 bucket for processed results
    """
    
    try:
        logger.info("Processing started")
        
        if 'Records' not in event:
            raise ValueError("Invalid event format: missing Records")
        
        results = []
        
        for record in event['Records']:
            if record.get('eventSource') != 'aws:s3':
                logger.warning("Skipping non-S3 event")
                continue
            
            s3_info = record.get('s3', {})
            bucket_info = s3_info.get('bucket', {})
            object_info = s3_info.get('object', {})
            
            bucket = bucket_info.get('name')
            key = object_info.get('key')
            
            if not bucket or not key:
                logger.error("Missing bucket or key in event")
                continue
            
            try:
                validated_bucket = validate_bucket_name(bucket)
                validated_key = validate_s3_key(key)
                
                validate_file_extension(validated_key)
                
                result, image_data = process_image(validated_bucket, validated_key)
                
                output_key = write_results_to_s3(result, validated_key)
                result['output_key'] = output_key
                
                send_notification({
                    'status': 'success',
                    'original_file': os.path.basename(validated_key),
                    'output_location': output_key
                })
                
                results.append(result)
                logger.info(f"Successfully processed: {sanitize_for_logging({'key': validated_key})}")
                
            except ValueError as ve:
                error_msg = str(ve)
                logger.error(f"Validation error: {error_msg}")
                results.append({
                    'key': 'REDACTED',
                    'status': 'failed',
                    'error': error_msg
                })
                
            except Exception as e:
                logger.error(f"Processing error: {str(e)}")
                results.append({
                    'key': 'REDACTED',
                    'status': 'failed',
                    'error': 'Internal processing error'
                })
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Processing complete',
                'processed_count': len(results)
            })
        }
        
    except Exception as e:
        logger.error(f"Lambda execution error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Processing failed',
                'error': 'Internal error'
            })
        }